6106 // looking at now (which is of type IndexedType). IdxSkip is the number of
6107 // indices from Idxs that should be left out when inserting into the resulting
6108 // struct. To is the result struct built so far, new insertvalue instructions
6109 // build on that.
6110 static Value *BuildSubAggregate(Value *From, Value *To, Type *IndexedType,
6111                                 SmallVectorImpl<unsigned> &Idxs,
6112                                 unsigned IdxSkip,
6113                                 BasicBlock::iterator InsertBefore) {
6114   StructType *STy = dyn_cast<StructType>(IndexedType);
6115   if (STy) {
6116     // Save the original To argument so we can modify it
6117     Value *OrigTo = To;
6118     // General case, the type indexed by Idxs is a struct
6119     for (unsigned i = 0, e = STy->getNumElements(); i != e; ++i) {
6120       // Process each struct element recursively
6121       Idxs.push_back(i);
6122       Value *PrevTo = To;
6123       To = BuildSubAggregate(From, To, STy->getElementType(i), Idxs, IdxSkip,
6124                              InsertBefore);
